206	void OpencoreImpl::WriteNtFile(FILE* fp) {
207	    int phnum = (int)phdr.size();
208	    Elf64_Nhdr elf_nhdr;
209	    elf_nhdr.n_namesz = NOTE_CORE_NAME_SZ;
210	    elf_nhdr.n_descsz = sizeof(lp64::File) * phnum + 2 * 8 + RoundUp(fileslen, 4);
211	    elf_nhdr.n_type = NT_FILE;
212	
213	    char magic[8];
214	    memset(magic, 0, sizeof(magic));
215	    snprintf(magic, NOTE_CORE_NAME_SZ, ELFCOREMAGIC);
216	
217	    fwrite(&elf_nhdr, sizeof(Elf64_Nhdr), 1, fp);
218	    fwrite(magic, sizeof(magic), 1, fp);
219	
220	    uint64_t number = phnum;
221	    fwrite(&number, 8, 1, fp);
222	    fwrite(&page_size, 8, 1, fp);
223	
224	    for (int index = 0; index < phnum; ++index)
225	        fwrite(&file[index], sizeof(lp64::File), 1, fp);
226	
227	    for (int index = 0; index < phnum; ++index)
228	        fwrite(maps[index].file.data(), maps[index].file.length() + 1, 1, fp);
229	}
