108	        fwrite(magic, sizeof(magic), 1, fp);
109	        fwrite(&prstatus[index], sizeof(Elf64_prstatus), 1, fp);
110	        if (!index) WriteCoreSignalInfo(fp);
111	        WriteCoreFpRegs(prstatus[index].pr_pid ,fp);
