def extract_messages_from_transcript(transcript_content: str) -> List[Dict]:
    """从 JSONL transcript 中提取消息，支持多种格式"""

    # 优先检测格式类型
    lines = [l.strip() for l in transcript_content.strip().split('\n') if l.strip()]
    if not lines:
        return []

    # 检测是否为 history.jsonl 格式（有 display 字段）
    first_line = lines[0]
    try:
        first_entry = json.loads(first_line)
        is_history_format = 'display' in first_entry
    except:
        is_history_format = False

    messages = []

    if is_history_format:
        # history.jsonl 格式: {"display": "...", "timestamp": ..., ...}
        # display 字段包含用户输入的命令/消息
        for line in lines:
            try:
                entry = json.loads(line)
                display = entry.get('display', '')

                # 跳过空消息
                if not display or len(display) < 3:
                    continue

                # 跳过系统命令（以 / 或 $ 开头的）
                if display.startswith('/') or display.startswith('$'):
                    # 如果是有效的问题/讨论，记录为用户消息
                    if len(display) > 10:
                        messages.append({
                            'role': 'user',
                            'content': strip_html_tags(display)
                        })
                    continue

                # 检查 pastedContents - 可能包含助手回复
                pasted = entry.get('pastedContents', {})
                if pasted:
                    for key, value in pasted.items():
                        if isinstance(value, dict) and 'content' in value:
                            content = value.get('content', '')
                            if content and len(content) > 20:
                                messages.append({
                                    'role': 'assistant',
                                    'content': content
                                })

                # display 通常是用户消息
                if len(display) > 10:
                    messages.append({
                        'role': 'user',
                        'content': strip_html_tags(display)
                    })

            except (json.JSONDecodeError, KeyError):
                continue
    else:
        # 标准 transcript 格式: {"type": "user/assistant", ...}
        for line in lines:
            try:
                entry = json.loads(line)
                msg_type = entry.get('type', '')

                # 提取用户消息
                if msg_type == 'user':
                    content = entry.get('message', {}).get('content', '')
                    if content and not entry.get('isMeta', False):
                        messages.append({
                            'role': 'user',
                            'content': strip_html_tags(content)
                        })

                # 提取助手消息
                elif msg_type == 'assistant':
                    text_content = entry.get('text', '')
                    if text_content:
                        messages.append({
                            'role': 'assistant',
                            'content': text_content
                        })
            except (json.JSONDecodeError, KeyError):
                continue

    return messages

